import { defineComponentSlotStyle } from "@yamada-ui/react"

export const nativePopoverStyle = defineComponentSlotStyle({
  base: {
    body: {
      alignItems: "flex-start",
      display: "flex",
      flex: "1",
      flexDirection: "column",
      gap: "{gap}",
    },
    content: {
      bg: "bg.float",
      borderColor: "border.muted",
      borderWidth: "1px",
      boxShadow: "sm",
      display: "flex",
      flexDirection: "column",
      focusVisibleRing: "none",
      gap: "{gap}",
      p: "{padding}",
      rounded: "l2",
    },
    footer: {
      alignItems: "center",
      display: "flex",
      gap: "{gap}",
      justifyContent: "flex-start",
    },
    header: {
      alignItems: "center",
      display: "flex",
      fontWeight: "semibold",
      gap: "{gap}",
      justifyContent: "flex-start",
    },
  },

  sizes: {
    xs: {
      content: {
        "--gap": "spaces.1",
        "--padding": "spaces.2",
        fontSize: "xs",
      },
    },
    sm: {
      content: {
        "--gap": "spaces.2",
        "--padding": "spaces.3",
        fontSize: "sm",
      },
    },
    md: {
      content: {
        "--gap": "spaces.3",
        "--padding": "spaces.4",
        fontSize: "md",
      },
    },
    lg: {
      content: {
        "--gap": "spaces.4",
        "--padding": "spaces.5",
        fontSize: "md",
      },
    },
  },

  defaultProps: {
    size: "md",
  },
})

export type NativePopoverStyle = typeof nativePopoverStyle

"use client"

import type { FC, PropsWithChildren } from "react"
import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { NativePopoverStyle } from "./native-popover.style"
import type {
  UseNativePopoverProps,
  UseNativePopoverReturn,
} from "./use-native-popover"
import { useMemo } from "react"
import { createSlotComponent, styled, cast } from "@yamada-ui/react"
import { nativePopoverStyle } from "./native-popover.style"
import { useNativePopover } from "./use-native-popover"

interface ComponentContext extends Pick<
  UseNativePopoverReturn,
  | "getAnchorProps"
  | "getBodyProps"
  | "getCloseTriggerProps"
  | "getContentProps"
  | "getFooterProps"
  | "getHeaderProps"
  | "getPositionerProps"
  | "getTriggerProps"
> {}

export interface NativePopoverRootProps
  extends
    UseNativePopoverProps,
    ThemeProps<NativePopoverStyle>,
    PropsWithChildren {}

const {
  ComponentContext,
  PropsContext: NativePopoverPropsContext,
  StyleContext,
  useComponentContext,
  usePropsContext: useNativePopoverPropsContext,
  withContext,
  useRootComponentProps,
} = createSlotComponent<
  NativePopoverRootProps,
  NativePopoverStyle,
  ComponentContext
>("native-popover", nativePopoverStyle)

export { NativePopoverPropsContext, useNativePopoverPropsContext }

/**
 * `NativePopover` is a component that floats around an element to display information using the native HTML Popover API.
 *
 * @see https://yamada-ui.com/docs/components/native-popover
 */
export const NativePopoverRoot: FC<NativePopoverRootProps> = (props) => {
  const [styleContext, { children, ...rest }] = useRootComponentProps(props)
  const {
    getAnchorProps,
    getBodyProps,
    getCloseTriggerProps,
    getContentProps,
    getFooterProps,
    getHeaderProps,
    getPositionerProps,
    getTriggerProps,
  } = useNativePopover(rest)
  const componentContext = useMemo(
    () => ({
      getAnchorProps,
      getBodyProps,
      getCloseTriggerProps,
      getContentProps,
      getFooterProps,
      getHeaderProps,
      getPositionerProps,
      getTriggerProps,
    }),
    [
      getAnchorProps,
      getBodyProps,
      getCloseTriggerProps,
      getContentProps,
      getFooterProps,
      getHeaderProps,
      getPositionerProps,
      getTriggerProps,
    ],
  )

  return (
    <StyleContext value={styleContext}>
      <ComponentContext value={componentContext}>{children}</ComponentContext>
    </StyleContext>
  )
}

export interface NativePopoverTriggerProps extends HTMLStyledProps<"button"> {}

export const NativePopoverTrigger = withContext<
  "button",
  NativePopoverTriggerProps
>("button", "trigger")({ asChild: true }, (props) => {
  const { getTriggerProps } = useComponentContext()

  return getTriggerProps(props)
})

export interface NativePopoverAnchorProps extends HTMLStyledProps {}

export const NativePopoverAnchor = withContext<"div", NativePopoverAnchorProps>(
  "div",
  "anchor",
)({ asChild: true }, (props) => {
  const { getAnchorProps } = useComponentContext()

  return getAnchorProps(props)
})

interface NativePopoverPositionerProps extends HTMLStyledProps {}

const NativePopoverPositioner = withContext<
  "div",
  NativePopoverPositionerProps
>("div", "positioner")({ asChild: true }, (props) => {
  const { getPositionerProps } = useComponentContext()

  return getPositionerProps(props)
})

export interface NativePopoverCloseTriggerProps extends HTMLStyledProps<"button"> {}

export const NativePopoverCloseTrigger = withContext<
  "button",
  NativePopoverCloseTriggerProps
>("button", { name: "CloseTrigger", slot: ["trigger", "close"] })(
  { asChild: true },
  (props) => {
    const { getCloseTriggerProps } = useComponentContext()

    return getCloseTriggerProps(props)
  },
)

export interface NativePopoverContentProps
  extends HTMLStyledProps, PropsWithChildren {}

export const NativePopoverContent = withContext<
  "div",
  NativePopoverContentProps
>(({ children, ...rest }) => {
  const { getContentProps } = useComponentContext()

  return (
    <NativePopoverPositioner>
      <styled.div {...getContentProps(cast<HTMLStyledProps>(rest))}>
        {children}
      </styled.div>
    </NativePopoverPositioner>
  )
}, "content")({
  suppressHydrationWarning: true,
})

export interface NativePopoverHeaderProps extends HTMLStyledProps {}

export const NativePopoverHeader = withContext<"div", NativePopoverHeaderProps>(
  "div",
  "header",
)(undefined, (props) => {
  const { getHeaderProps } = useComponentContext()

  return getHeaderProps(props)
})

export interface NativePopoverBodyProps extends HTMLStyledProps {}

export const NativePopoverBody = withContext<"div", NativePopoverBodyProps>(
  "div",
  "body",
)(undefined, (props) => {
  const { getBodyProps } = useComponentContext()

  return getBodyProps(props)
})

export interface NativePopoverFooterProps extends HTMLStyledProps {}

export const NativePopoverFooter = withContext<"div", NativePopoverFooterProps>(
  "div",
  "footer",
)(undefined, (props) => {
  const { getFooterProps } = useComponentContext()

  return getFooterProps(props)
})

"use client"

import type { MouseEvent, RefObject } from "react"
import type { Direction, PropGetter } from "@yamada-ui/react"
import type { UsePopperProps } from "../../hooks/use-popper"
import { useCallback, useId, useRef } from "react"
import {
  useEnvironment,
  ariaAttr,
  assignRef,
  cx,
  dataAttr,
  handlerAll,
  mergeRefs,
} from "@yamada-ui/react"
import { usePopper } from "../../hooks/use-popper"

export interface UseNativePopoverProps extends UsePopperProps<"button"> {
  /**
   * If `true`, the popover will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The placement of the popper relative to its reference.
   *
   * @default 'end'
   */
  placement?: Direction
  /**
   * The mode of the popover.
   *
   * @default 'auto'
   */
  popover?: "" | "auto" | "hint" | "manual" | true
  /**
   * The target element ID for the popover trigger.
   * If not provided, a generated ID will be used.
   */
  popoverTarget?: string
  /**
   * The action for the popover target.
   *
   * @default 'toggle'
   */
  popoverTargetAction?: "hide" | "show" | "toggle"
  /**
   * Update the position of the floating element, re-rendering the component if required.
   */
  updateRef?: RefObject<() => void>
}

export const useNativePopover = ({
  autoUpdate,
  disabled = false,
  elements,
  flip,
  gutter,
  matchWidth,
  middleware,
  offset,
  placement = "end",
  platform,
  popover = "auto",
  popoverTarget,
  popoverTargetAction = "toggle",
  preventOverflow,
  strategy,
  transform,
  updateRef,
  whileElementsMounted,
}: UseNativePopoverProps = {}) => {
  const { getDocument } = useEnvironment()
  const headerId = useId()
  const bodyId = useId()
  const generatedContentId = useId()
  const contentId = popoverTarget ?? generatedContentId
  const anchorRef = useRef<HTMLElement>(null)
  const triggerRef = useRef<HTMLButtonElement>(null)
  const contentRef = useRef<HTMLDivElement>(null)
  const { refs, update, getPopperProps } = usePopper<"button">({
    autoUpdate,
    elements,
    flip,
    gutter,
    matchWidth,
    middleware,
    offset,
    placement,
    platform,
    preventOverflow,
    strategy,
    transform,
    whileElementsMounted,
  })

  assignRef(updateRef, update)

  const onClick = useCallback(
    (ev: MouseEvent<HTMLButtonElement>) => {
      if (!disabled) return

      ev.preventDefault()
      ev.stopPropagation()
    },
    [disabled],
  )

  const getTriggerProps: PropGetter<"button"> = useCallback(
    ({ ref, ...props } = {}) => {
      return {
        type: "button",
        "aria-controls": contentId,
        "aria-disabled": ariaAttr(disabled),
        "aria-haspopup": "dialog",
        popoverTarget: contentId,
        popoverTargetAction,
        role: "button",
        ...props,
        ref: mergeRefs(ref, triggerRef, (node) => {
          if (anchorRef.current == null) refs.setReference(node)
        }),
        onClick: handlerAll(props.onClick, onClick),
      }
    },
    [contentId, disabled, onClick, popoverTargetAction, refs],
  )

  const getAnchorProps: PropGetter = useCallback(
    ({ ref, ...props } = {}) => ({
      ...props,
      ref: mergeRefs(ref, anchorRef, refs.setReference),
    }),
    [refs.setReference],
  )

  const getPositionerProps: PropGetter = useCallback(
    (props) => getPopperProps(props),
    [getPopperProps],
  )

  const getContentProps: PropGetter = useCallback(
    ({
      ref,
      "aria-describedby": ariaDescribedby,
      "aria-labelledby": ariaLabelledby,
      ...props
    } = {}) => {
      const hasHeader = !!getDocument()?.getElementById(headerId)
      const hasBody = !!getDocument()?.getElementById(bodyId)

      return {
        id: contentId,
        "aria-describedby": cx(ariaDescribedby, hasBody ? bodyId : undefined),
        "aria-labelledby": cx(ariaLabelledby, hasHeader ? headerId : undefined),
        "data-popup": dataAttr(true),
        popover: popover === true ? "" : popover,
        role: "dialog",
        tabIndex: -1,
        ...props,
        ref: mergeRefs(ref, contentRef),
      }
    },
    [getDocument, headerId, bodyId, contentId, popover],
  )

  const getHeaderProps: PropGetter = useCallback(
    (props) => ({ id: headerId, ...props }),
    [headerId],
  )

  const getBodyProps: PropGetter = useCallback(
    (props) => ({ id: bodyId, ...props }),
    [bodyId],
  )

  const getFooterProps: PropGetter = useCallback((props) => ({ ...props }), [])

  const getCloseTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => {
      return {
        popoverTarget: contentId,
        popoverTargetAction: "hide",
        ...props,
      }
    },
    [contentId],
  )

  return {
    getAnchorProps,
    getBodyProps,
    getCloseTriggerProps,
    getContentProps,
    getFooterProps,
    getHeaderProps,
    getPositionerProps,
    getTriggerProps,
  }
}

export type UseNativePopoverReturn = ReturnType<typeof useNativePopover>
